import React, { useState } from 'react';

export default function PricingToggle({ headline, description, plans, annual_discount }) {
  const [annual, setAnnual] = useState(false);
  const discount = annual_discount || 20;

  return (
    <section style={{ padding: '4rem 2rem', textAlign: 'center', fontFamily: 'var(--font-body, system-ui, sans-serif)' }}>
      {headline && <h2 style={{ fontSize: '2rem', color: 'white', margin: '0 0 0.5rem' }}>{headline}</h2>}
      {description && <p style={{ color: '#adadb0', margin: '0 0 2rem', fontSize: '1.1rem' }}>{description}</p>}

      <div style={{ display: 'inline-flex', alignItems: 'center', gap: '0.75rem', marginBottom: '2.5rem', background: '#1f1f23', padding: '0.25rem', borderRadius: '2rem' }}>
        <button
          onClick={() => setAnnual(false)}
          style={{
            padding: '0.5rem 1.5rem', borderRadius: '2rem', border: 'none', cursor: 'pointer',
            background: !annual ? 'var(--primary, #2563eb)' : 'transparent',
            color: !annual ? '#111' : '#adadb0', fontWeight: 600, fontSize: '0.9rem',
          }}
        >Monthly</button>
        <button
          onClick={() => setAnnual(true)}
          style={{
            padding: '0.5rem 1.5rem', borderRadius: '2rem', border: 'none', cursor: 'pointer',
            background: annual ? 'var(--primary, #2563eb)' : 'transparent',
            color: annual ? '#111' : '#adadb0', fontWeight: 600, fontSize: '0.9rem',
          }}
        >Annual <span style={{ fontSize: '0.75rem', opacity: 0.8 }}>(-{discount}%)</span></button>
      </div>

      <div style={{ display: 'flex', gap: '1.5rem', justifyContent: 'center', flexWrap: 'wrap', maxWidth: '1000px', margin: '0 auto' }}>
        {(plans || []).map((plan, i) => {
          const price = annual ? Math.round(plan.price * (1 - discount / 100)) : plan.price;
          return (
            <div key={i} style={{
              background: '#1f1f23', border: plan.featured ? '2px solid var(--primary, #2563eb)' : '1px solid #2a2a2e',
              borderRadius: '12px', padding: '2rem', minWidth: '280px', flex: '1', maxWidth: '320px', position: 'relative',
            }}>
              {plan.featured && (
                <span style={{
                  position: 'absolute', top: '-12px', left: '50%', transform: 'translateX(-50%)',
                  background: 'var(--primary, #2563eb)', color: '#111', fontSize: '0.75rem',
                  fontWeight: 700, padding: '0.25rem 1rem', borderRadius: '20px',
                }}>Most Popular</span>
              )}
              <h3 style={{ color: 'white', margin: '0 0 0.5rem', fontSize: '1.25rem' }}>{plan.name}</h3>
              <div style={{ margin: '0.5rem 0 1.5rem' }}>
                <span style={{ fontSize: '2.5rem', fontWeight: 800, color: 'white' }}>${price}</span>
                <span style={{ color: '#8b8b90', fontSize: '1rem' }}>/mo</span>
              </div>
              <ul style={{ listStyle: 'none', padding: 0, margin: '0 0 2rem' }}>
                {(plan.features || []).map((f, j) => (
                  <li key={j} style={{ padding: '0.5rem 0', color: '#adadb0', borderBottom: '1px solid #2a2a2e', fontSize: '0.9rem' }}>{f}</li>
                ))}
              </ul>
              <a href={plan.cta_url || '#'} style={{
                display: 'block', padding: '0.75rem', borderRadius: '8px', textDecoration: 'none', fontWeight: 600, textAlign: 'center',
                background: plan.featured ? 'var(--primary, #2563eb)' : '#2a2a2e',
                color: plan.featured ? '#111' : 'white',
              }}>{plan.cta_text || 'Get Started'}</a>
            </div>
          );
        })}
      </div>
    </section>
  );
}
